function toFV(v) {
  if (v === null || v === undefined) return { nullValue: null };
  if (typeof v === 'string') return { stringValue: v };
  if (typeof v === 'boolean') return { booleanValue: v };
  if (typeof v === 'number') {
    if (Number.isInteger(v)) return { integerValue: String(v) };
    return { doubleValue: v };
  }
  if (Array.isArray(v)) return { arrayValue: { values: v.map(toFV) } };
  if (typeof v === 'object') {
    var fields = {};
    for (var k in v) fields[k] = toFV(v[k]);
    return { mapValue: { fields: fields } };
  }
  return { nullValue: null };
}

// الـ input = WhatsApp API responses
var waItems = $input.all();

// جيب الـ decisions من الـ node الصح
var decisions = [];
try {
  var autoAll = $('Decide Who To Notify').all();
  for (var a = 0; a < autoAll.length; a++) {
    if (!autoAll[a].json.skip) decisions.push(autoAll[a].json);
  }
} catch(e) {}

if (!decisions.length) {
  try {
    var manualAll = $('Manual: Prepare Notify Data').all();
    for (var m = 0; m < manualAll.length; m++) {
      if (!manualAll[m].json.skip) decisions.push(manualAll[m].json);
    }
  } catch(e) {}
}

if (!decisions.length) return [];

var entriesByTask = {};

for (var i = 0; i < decisions.length; i++) {
  var decision = decisions[i];
  var waRes = waItems[i] ? waItems[i].json : null;
  if (!waRes || !waRes.messages || !waRes.contacts) continue;

  var phone = waRes.contacts[0] ? waRes.contacts[0].wa_id : null;
  var msgId = waRes.messages[0] ? waRes.messages[0].id : null;
  if (!phone || !msgId || !decision.taskId) continue;

  var isManual = decision._source === 'manual';
  var newEntry = {
    source:        isManual ? 'manual_notify' : 'system',
    type:          isManual ? 'manual_notify_sent' : 'reminder_sent',
    text:          isManual
      ? ('تم إرسال تنبيه يدوي لـ ' + decision.memberName + ' (+' + phone + ')')
      : ('Template reminder sent to ' + decision.memberName + ' (+' + phone + ')'),
    memberId:      decision.memberId,
    memberName:    decision.memberName,
    sentMessageId: msgId,
    timestamp:     Date.now()
  };

  var tId = decision.taskId;
  if (!entriesByTask[tId]) entriesByTask[tId] = [];
  entriesByTask[tId].push(newEntry);
}

var output = [];
for (var taskId in entriesByTask) {
  output.push({ json: { taskId: taskId, newEntries: entriesByTask[taskId] } });
}
return output;

function fromFV(v) {
  if (v == null) return null;
  if ('stringValue' in v) return v.stringValue;
  if ('integerValue' in v) return parseInt(v.integerValue);
  if ('doubleValue' in v) return parseFloat(v.doubleValue);
  if ('booleanValue' in v) return v.booleanValue;
  if ('nullValue' in v) return null;
  if ('timestampValue' in v) return v.timestampValue;
  if ('arrayValue' in v) return (v.arrayValue.values || []).map(fromFV);
  if ('mapValue' in v) return fromFF(v.mapValue.fields || {});
  return null;
}
function fromFF(fields) {
  const o = {};
  for (const k in fields) o[k] = fromFV(fields[k]);
  return o;
}
function toFV(v) {
  if (v === null || v === undefined) return { nullValue: null };
  if (typeof v === 'string') return { stringValue: v };
  if (typeof v === 'boolean') return { booleanValue: v };
  if (typeof v === 'number') {
    if (Number.isInteger(v)) return { integerValue: String(v) };
    return { doubleValue: v };
  }
  if (Array.isArray(v)) return { arrayValue: { values: v.map(toFV) } };
  if (typeof v === 'object') {
    const fields = {};
    for (const k in v) fields[k] = toFV(v[k]);
    return { mapValue: { fields } };
  }
  return { nullValue: null };
}

const buildItems = $('Build Log Entry').all();
const entryMap = {};
for (const item of buildItems) {
  const tId = item.json.taskId;
  const entries = item.json.newEntries || [];
  if (!entryMap[tId]) entryMap[tId] = [];
  entryMap[tId].push(...entries);
}

const tasks = $input.all();
const output = [];

for (const taskItem of tasks) {
  const taskDoc = taskItem.json;
  const taskId = taskDoc.name.split('/').pop();

  const newEntries = entryMap[taskId];
  if (!newEntries || newEntries.length === 0) continue;

  const currentLogFV = taskDoc.fields?.activityLog;
  const currentLog = currentLogFV
    ? (currentLogFV.arrayValue?.values || []).map(fromFV)
    : [];

  let updatedLog = [...currentLog];
  for (const newEntry of newEntries) {
    const exists = updatedLog.some(e =>
      e && e.sentMessageId === newEntry.sentMessageId && e.memberId === newEntry.memberId
    );
    if (!exists) updatedLog.push(newEntry);
  }

  output.push({
    json: {
      taskId,
      firestoreBody: { fields: { activityLog: toFV(updatedLog) } }
    }
  });
}

return output;

const body = $input.item.json.body || $input.item.json;

if (body.event !== 'manual_notify') {
  return { json: { skip: true, reason: 'not_manual_notify_event' } };
}

const task      = body.task      || {};
const phones    = body.phones    || [];
const assignees = body.assignees || [];
const memberIds = body.memberIds || [];

if (!task.id || !phones.length) {
  return { json: { skip: true, reason: 'missing_task_or_phones' } };
}

const deadline = (task.deadline && task.deadline !== '') ? new Date(task.deadline) : null;
const deadlineStr = deadline && !isNaN(deadline)
  ? deadline.toLocaleString('en-GB', {
      day: '2-digit', month: 'short',
      hour: '2-digit', minute: '2-digit',
      hour12: false, timeZone: 'Africa/Cairo'
    })
  : 'غير محدد';

const progress = String(task.progress || 0);

const results = phones.map(function(phone, i) {
  const cleanPhone = (phone || '').replace(/\D/g, '');
  const memberName = assignees[i] || 'الموظف';
  const firstName  = memberName.split(' ')[0];
  // استخدم الـ Firestore memberId لو موجود، غير كده استخدم الرقم
  const memberId   = memberIds[i] || cleanPhone;
  return {
    json: {
      skip: false,
      taskId:      task.id,
      memberId:    memberId,
      memberName:  memberName,
      memberPhone: cleanPhone,
      firstName:   firstName,
      taskName:    task.name || 'Task',
      deadlineStr: deadlineStr,
      progress:    progress,
      currentActivityLog: [],
      _source: 'manual'
    }
  };
});

return results;
